  let output = '';
  for (let i = 0; i < string.length; i++) {
    const code = string.charCodeAt(i);
    if (code >= UPPER_A && code <= UPPER_Z) {
      output += '-' + String.fromCharCode(code + UPPER_TO_LOWER);
    } else {
      output += string[i];
    }
  }

  return output.startsWith('ms-') ? '-' + output : output;
