  if (!map) return null;
  const names = styleSheet.names.get(cs.componentId);
  if (!names) return null;
  let css = '';
  for (const name of names) {
    const compiled = map.get(name);
    if (!compiled) return null;
    css += compiled;
  }
  return css;
}

